#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

__global__ void initialize_data_kernel(float* f) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * N;
    if (idx >= total) return;

    int i = idx % N;
    int j = idx / N;

    if (i == 0 || i == N-1) {
        f[idx] = sinf(j * 2 * M_PI / (N - 1));
    }
    else if (j == 0 || j == N-1) {
        f[idx] = sinf(i * 2 * M_PI / (N - 1));
    }
    else {
        f[idx] = 0.0f;
    }
}

__global__ void compute_step_kernel(float* f, float* f_old, float* error_ptr) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_inner = (N-2) * (N-2);

    if (idx >= total_inner) return;

    int i = 1 + (idx % (N-2));
    int j = 1 + (idx / (N-2));

    float t = 0.25f * (f_old[IDX(i-1,j)] +
                       f_old[IDX(i+1,j)] +
                       f_old[IDX(i,j-1)] +
                       f_old[IDX(i,j+1)]);

    float df = t - f_old[IDX(i, j)];
    f[IDX(i,j)] = t;

    error_ptr[idx] = df * df;
}

__global__ void copy_inner_kernel(float* f, float* f_old) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_inner = (N-2) * (N-2);

    if (idx >= total_inner) return;

    int i = 1 + (idx % (N-2));
    int j = 1 + (idx / (N-2));

    f_old[IDX(i,j)] = f[IDX(i,j)];
}

__global__ void sum_error_kernel(float* error_ptr, float* result, int count) {
    float shared_sum = 0.0f;

    // Simple summation for the block performed by thread 0
    if (threadIdx.x == 0) {
        for (int i = 0; i < count; ++i) {
            shared_sum += error_ptr[i];
        }
        *result = sqrtf(shared_sum / (N * N));
    }
}

void initialize_data(float* f_dev) {
    int total = N * N;
    int threads = 256;
    int blocks = (total + threads - 1) / threads;
    initialize_data_kernel<<<blocks, threads>>>(f_dev);
    cudaDeviceSynchronize();
}

int main () {

  auto start_time = std::chrono::steady_clock::now();

  float* f_dev;
  float* f_old_dev;
  float* error_dev;

  cudaMalloc(&f_dev, N * N * sizeof(float));
  cudaMalloc(&f_old_dev, N * N * sizeof(float));
  cudaMalloc(&error_dev, (N-2)*(N-2) * sizeof(float));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  float error_result;

  initialize_data(f_dev);
  initialize_data(f_old_dev);

  const int max_iters = 10000;
  int num_iters = 0;

  int threads = 256;
  int inner_size = (N-2) * (N-2);
  int blocks = (inner_size + threads - 1) / threads;

  auto start = std::chrono::steady_clock::now();

  while (tolerance < error && num_iters < max_iters) {

    error = 0.f;

    compute_step_kernel<<<blocks, threads>>>(f_dev, f_old_dev, error_dev);

    copy_inner_kernel<<<blocks, threads>>>(f_dev, f_old_dev);

    sum_error_kernel<<<1, 1>>>(error_dev, &error_result, inner_size);
    cudaDeviceSynchronize();

    error = error_result;

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (tolerance >= error && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    cudaFree(f_dev);
    cudaFree(f_old_dev);
    cudaFree(error_dev);
    return -1;
  }

  cudaFree(f_dev);
  cudaFree(f_old_dev);
  cudaFree(error_dev);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
